95	func loadFromRunStore(workingDir string) ([]Attempt, error) {
96		dir := filepath.Join(workingDir, runStoreSubdir)
97		entries, err := os.ReadDir(dir)
98		if err != nil {
99			if os.IsNotExist(err) {
100				return nil, nil
101			}
102			return nil, fmt.Errorf("read run store: %w", err)
103		}
104		out := make([]Attempt, 0, len(entries))
105		for _, entry := range entries {
106			if entry.IsDir() || !strings.HasSuffix(entry.Name(), ".json") {
107				continue
108			}
109			raw, err := os.ReadFile(filepath.Join(dir, entry.Name()))
110			if err != nil {
111				continue
112			}
113			var rec runRecord
114			if err := json.Unmarshal(raw, &rec); err != nil || rec.ID == "" {
115				continue
116			}
117			// Only try-layer records correspond to execute-bead attempts.
118			// Run-layer records (per-invocation harness sessions) are noise
119			// for Story 11 aggregations; skip them. Empty layer is treated
120			// as try for forward-compat with writers that omit it.
121			layer := strings.ToLower(rec.Layer)
122			if layer != "" && layer != "try" {
123				continue
124			}
125			a := Attempt{
126				AttemptID:  rec.ID,
127				BeadID:     rec.BeadID,
128				Harness:    rec.Harness,
129				Provider:   rec.Provider,
130				Model:      rec.Model,
131				Status:     rec.Status,
132				Outcome:    rec.Outcome,
133				CostUSD:    rec.CostUSD,
134				DurationMS: rec.DurationMs,
135				ExitCode:   rec.ExitCode,
136				StartedAt:  parseTime(rec.StartedAt),
137				FinishedAt: parseTime(rec.CompletedAt),
138				Source:     SourceRunStore,
139			}
140			out = append(out, a)
141		}
142		return out, nil
143	}
