209	// routingFacts is the harness/provider/model the most recent kind:routing
210	// or kind:escalation-summary event recorded for a bead. Used to fill in
211	// blanks on legacy attempts whose result.json predates those fields.
212	type routingFacts struct {
213		Harness  string
214		Provider string
215		Model    string
216	}
217	
218	// loadRoutingEnrichment scans the bead store and indexes the most recent
219	// routing/escalation-summary facts per bead. Best-effort: a missing or
220	// unreadable bead store yields an empty map, never an error, since the
221	// loader still has authoritative data on each result.
222	func loadRoutingEnrichment(workingDir string) (map[string]routingFacts, error) {
223		store := bead.NewStore(filepath.Join(workingDir, ".ddx"))
224		beads, err := store.ReadAll()
225		if err != nil {
226			// Return an empty map so missing bead store does not abort
227			// metrics loading.
228			return map[string]routingFacts{}, nil
229		}
230		out := make(map[string]routingFacts, len(beads))
231		for _, b := range beads {
232			facts := routingFromExtra(b.Extra)
233			if facts.Harness == "" && facts.Provider == "" && facts.Model == "" {
234				continue
235			}
236			out[b.ID] = facts
237		}
238		return out, nil
239	}
240	
241	// routingFromExtra walks bead.Extra["events"] in chronological order and
242	// returns the last kind:routing or kind:escalation-summary facts. Both
243	// kinds carry resolved_provider / resolved_model in the JSON body; the
244	// escalation summary additionally exposes a tiers_attempted list whose
245	// final entry is the winning tier.
246	func routingFromExtra(extra map[string]any) routingFacts {
247		if extra == nil {
248			return routingFacts{}
249		}
250		raw, ok := extra["events"]
251		if !ok {
252			return routingFacts{}
253		}
254		items, ok := raw.([]any)
255		if !ok {
256			return routingFacts{}
257		}
258		type ev struct {
259			kind      string
260			body      string
261			createdAt time.Time
262		}
263		events := make([]ev, 0, len(items))
264		for _, item := range items {
265			m, ok := item.(map[string]any)
266			if !ok {
267				continue
268			}
269			kind, _ := m["kind"].(string)
270			if kind != "routing" && kind != "escalation-summary" {
271				continue
272			}
273			body, _ := m["body"].(string)
274			var createdAt time.Time
275			if v, ok := m["created_at"].(string); ok {
276				if t, err := time.Parse(time.RFC3339, v); err == nil {
277					createdAt = t
278				}
279			}
280			events = append(events, ev{kind: kind, body: body, createdAt: createdAt})
281		}
282		sort.SliceStable(events, func(i, j int) bool {
283			return events[i].createdAt.Before(events[j].createdAt)
284		})
285		var out routingFacts
286		for _, e := range events {
287			switch e.kind {
288			case "routing":
289				var body struct {
290					ResolvedProvider string `json:"resolved_provider"`
291					ResolvedModel    string `json:"resolved_model"`
292					RequestedHarness string `json:"requested_harness"`
293				}
294				if err := json.Unmarshal([]byte(e.body), &body); err != nil {
295					continue
296				}
297				if body.ResolvedProvider != "" {
298					out.Provider = body.ResolvedProvider
299				}
300				if body.ResolvedModel != "" {
301					out.Model = body.ResolvedModel
302				}
303				if body.RequestedHarness != "" {
304					out.Harness = body.RequestedHarness
305				}
306			case "escalation-summary":
307				var body struct {
308					WinningTier    string `json:"winning_tier"`
309					TiersAttempted []struct {
310						Tier    string `json:"tier"`
311						Harness string `json:"harness"`
312						Model   string `json:"model"`
313						Status  string `json:"status"`
314					} `json:"tiers_attempted"`
315				}
316				if err := json.Unmarshal([]byte(e.body), &body); err != nil {
317					continue
318				}
319				// Use the winning tier when one exists, else the last
320				// attempted tier.
321				pick := body.WinningTier
322				for _, t := range body.TiersAttempted {
323					if pick != "" && t.Tier == pick {
324						if t.Harness != "" {
325							out.Harness = t.Harness
326						}
327						if t.Model != "" {
328							out.Model = t.Model
329						}
330						break
331					}
332				}
333				if pick == "" && len(body.TiersAttempted) > 0 {
334					last := body.TiersAttempted[len(body.TiersAttempted)-1]
335					if last.Harness != "" {
336						out.Harness = last.Harness
337					}
338					if last.Model != "" {
339						out.Model = last.Model
340					}
341				}
342			}
343		}
344		return out
345	}
346	
347	func applyEnrichment(a *Attempt, enrich map[string]routingFacts) {
348		if a.BeadID == "" {
349			return
350		}
351		facts, ok := enrich[a.BeadID]
352		if !ok {
353			return
354		}
355		if a.Harness == "" {
356			a.Harness = facts.Harness
357		}
358		if a.Provider == "" {
359			a.Provider = facts.Provider
360		}
361		if a.Model == "" {
362			a.Model = facts.Model
363		}
364	}
365	
366	func parseTime(s string) time.Time {
367		if s == "" {
368			return time.Time{}
369		}
370		if t, err := time.Parse(time.RFC3339Nano, s); err == nil {
371			return t
372		}
373		if t, err := time.Parse(time.RFC3339, s); err == nil {
374			return t
375		}
376		return time.Time{}
377	}
