805	func (r *queryResolver) efficacySnapshot(ctx context.Context, since, until, projectID *string) (efficacySnapshot, error) {
806		projectRoot := r.workingDir(ctx)
807		if projectID != nil && strings.TrimSpace(*projectID) != "" {
808			projectRoot = r.projectRoot(ctx, strings.TrimSpace(*projectID))
809		}
810		startedAfter, err := parseOptionalEfficacyTime("since", since)
811		if err != nil {
812			return efficacySnapshot{}, err
813		}
814		startedBefore, err := parseOptionalEfficacyTime("until", until)
815		if err != nil {
816			return efficacySnapshot{}, err
817		}
818		logDir := agent.SessionLogDirForWorkDir(projectRoot)
819		query := agent.SessionIndexQuery{
820			StartedAfter:  startedAfter,
821			StartedBefore: startedBefore,
822		}
823		cacheKey := sessionEfficacyCacheKey(logDir, startedAfter, startedBefore)
824		fingerprint, err := sessionEfficacyIndexFingerprint(logDir, query)
825		if err != nil {
826			return efficacySnapshot{}, err
827		}
828		sessionEfficacyCache.Lock()
829		if sessionEfficacyCache.byQuery == nil {
830			sessionEfficacyCache.byQuery = map[string]sessionEfficacyCacheEntry{}
831		}
832		if cached, ok := sessionEfficacyCache.byQuery[cacheKey]; ok && cached.fingerprint == fingerprint {
833			sessionEfficacyCache.Unlock()
834			return cached.snapshot, nil
835		}
836		sessionEfficacyCache.Unlock()
837	
838		entries, err := agent.ReadSessionIndex(logDir, query)
839		if err != nil {
840			return efficacySnapshot{}, err
841		}
842		snap := buildSessionIndexEfficacySnapshot(entries)
843		sessionEfficacyCache.Lock()
844		sessionEfficacyCache.byQuery[cacheKey] = sessionEfficacyCacheEntry{fingerprint: fingerprint, snapshot: snap}
845		sessionEfficacyCache.Unlock()
846		return snap, nil
847	}
