860	func sessionEfficacyIndexFingerprint(logDir string, query agent.SessionIndexQuery) (string, error) {
861		files, err := agent.SessionIndexShardFiles(logDir, query)
862		if err != nil {
863			return "", err
864		}
865		parts := make([]string, 0, len(files))
866		for _, file := range files {
867			info, err := os.Stat(file)
868			if os.IsNotExist(err) {
869				continue
870			}
871			if err != nil {
872				return "", err
873			}
874			parts = append(parts, fmt.Sprintf("%s:%d:%d", file, info.Size(), info.ModTime().UnixNano()))
875		}
876		return strings.Join(parts, "|"), nil
877	}
