879	func parseOptionalEfficacyTime(name string, raw *string) (*time.Time, error) {
880		if raw == nil || strings.TrimSpace(*raw) == "" {
881			return nil, nil
882		}
883		value := strings.TrimSpace(*raw)
884		for _, layout := range []string{time.RFC3339Nano, time.RFC3339, "2006-01-02"} {
885			if parsed, err := time.Parse(layout, value); err == nil {
886				utc := parsed.UTC()
887				return &utc, nil
888			}
889		}
890		return nil, fmt.Errorf("%s must be RFC3339 or YYYY-MM-DD, got %q", name, value)
891	}
