935				attemptDetails[rowKey] = append(attemptDetails[rowKey], &EfficacyAttempt{
936					BeadID:            attempt.BeadID,
937					Outcome:           attempt.Outcome,
938					DurationMs:        attempt.DurationMs,
939					CostUsd:           attempt.CostUsd,
940					EvidenceBundleURL: attempt.EvidencePath,
941				})
942			}
943			parts := strings.Split(rowKey, "|")
944			row := &EfficacyRow{
945				RowKey:             rowKey,
946				Harness:            parts[0],
947				Provider:           parts[1],
948				Model:              parts[2],
949				Attempts:           len(group),
950				Successes:          successes,
951				SuccessRate:        float64(successes) / float64(len(group)),
952				MedianInputTokens:  medianInt(inputTokens),
953				MedianOutputTokens: medianInt(outputTokens),
954				MedianDurationMs:   medianInt(durations),
955				MedianCostUsd:      medianFloatPtr(costs),
956			}
957			if row.SuccessRate < efficacyWarningFloor {
958				row.Warning = &EfficacyWarning{Kind: "below-adaptive-floor", Threshold: floatPtr(efficacyWarningFloor)}
959			}
960			rows = append(rows, row)
961		}
962		sort.Slice(rows, func(i, j int) bool {
963			if rows[i].SuccessRate != rows[j].SuccessRate {
964				return rows[i].SuccessRate > rows[j].SuccessRate
965			}
966			return rows[i].RowKey < rows[j].RowKey
967		})
968	
969		return efficacySnapshot{rows: rows, attempts: attemptDetails}

