140	// stablePageBounds computes the [startIdx, endIdx) slice window using stable
141	// ID-based cursors. ids must contain the stable key for each edge in order.
142	func stablePageBounds(ids []string, after, before *string) (startIdx, endIdx int) {
143		startIdx = 0
144		endIdx = len(ids)
145		if after != nil {
146			if afterID, ok := decodeStableCursor(*after); ok {
147				for i, id := range ids {
148					if id == afterID {
149						startIdx = i + 1
150						break
151					}
152				}
153			}
154		}
155		if before != nil {
156			if beforeID, ok := decodeStableCursor(*before); ok {
157				for i, id := range ids {
158					if id == beforeID {
159						endIdx = i
160						break
161					}
162				}
163			}
164		}
165		if startIdx > endIdx {
166			startIdx = endIdx
167		}
168		return startIdx, endIdx
169	}
