171	func workerConnectionFrom(workers []*Worker, first *int, after *string, last *int, before *string) *WorkerConnection {
172		all := make([]*WorkerEdge, len(workers))
173		ids := make([]string, len(workers))
174		for i, w := range workers {
175			all[i] = &WorkerEdge{Node: w, Cursor: encodeStableCursor(w.ID)}
176			ids[i] = w.ID
177		}
178		startIdx, endIdx := stablePageBounds(ids, after, before)
179		slice := all[startIdx:endIdx]
180		truncByFirst, truncByLast := false, false
181		if first != nil && *first >= 0 && *first < len(slice) {
182			slice = slice[:*first]
183			truncByFirst = true
184		}
185		if last != nil && *last >= 0 && *last < len(slice) {
186			slice = slice[len(slice)-*last:]
187			truncByLast = true
188		}
189		pageInfo := &PageInfo{
190			HasPreviousPage: startIdx > 0 || truncByLast,
191			HasNextPage:     endIdx < len(all) || truncByFirst,
192		}
193		if len(slice) > 0 {
194			pageInfo.StartCursor = &slice[0].Cursor
195			pageInfo.EndCursor = &slice[len(slice)-1].Cursor
196		}
197		return &WorkerConnection{Edges: slice, PageInfo: pageInfo, TotalCount: len(all)}
198	}
