// resolver_agent_metrics.go implements the agentMetrics(window, groupBy)
// query (Story 11). Aggregations are computed from the agentmetrics package
// (run-store first, .ddx/executions bundles fallback) and cached per
// (project, axis, window) keyed on a revision fingerprint of the underlying
// data sources. The fingerprint covers the run-store dir, the bundles dir,
// and the .ddx/beads-archive.jsonl file so the cache survives an ADR-004
// archive move (closed beads moved out of beads.jsonl into beads-archive
// flip the fingerprint and force a re-aggregate).
package graphql

import (
	"context"
	"crypto/sha256"
	"fmt"
	"os"
	"path/filepath"
	"sort"
	"sync"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/agentmetrics"
)

// agentMetricsCacheEntry is one cached aggregation. fingerprint is the
// revision string the entry was computed against; on lookup the resolver
// recomputes the current fingerprint and serves the entry only when they
// match.
type agentMetricsCacheEntry struct {
	fingerprint string
	result      *AgentMetricsResult
}

// agentMetricsCache is process-global. Multi-project servers key by the
// effective workingDir so two projects never collide.
var agentMetricsCache = struct {
	sync.Mutex
	byKey map[string]agentMetricsCacheEntry
}{byKey: map[string]agentMetricsCacheEntry{}}

// AgentMetrics is the resolver for the agentMetrics field.
func (r *queryResolver) AgentMetrics(ctx context.Context, window AgentMetricsWindow, groupBy AgentMetricsAxis) (*AgentMetricsResult, error) {
	if !window.IsValid() {
		return nil, fmt.Errorf("agentMetrics: invalid window %q", window)
	}
	if !groupBy.IsValid() {
		return nil, fmt.Errorf("agentMetrics: invalid groupBy %q", groupBy)
	}
	wd := r.workingDir(ctx)
	fp := agentMetricsFingerprint(wd)
	cacheKey := wd + "|" + string(window) + "|" + string(groupBy)

	agentMetricsCache.Lock()
	if cached, ok := agentMetricsCache.byKey[cacheKey]; ok && cached.fingerprint == fp {
		agentMetricsCache.Unlock()
		return cached.result, nil
	}
	agentMetricsCache.Unlock()

	attempts, err := agentmetrics.LoadAttempts(wd)
	if err != nil {
		return nil, fmt.Errorf("agentMetrics: load attempts: %w", err)
	}
	cutoff := time.Now().UTC().Add(-windowDuration(window))
	rows := buildAgentMetricsRows(attempts, cutoff, groupBy)
	result := &AgentMetricsResult{
		Window:   window,
		GroupBy:  groupBy,
		Revision: fp,
		Rows:     rows,
	}
	agentMetricsCache.Lock()
	agentMetricsCache.byKey[cacheKey] = agentMetricsCacheEntry{fingerprint: fp, result: result}
	agentMetricsCache.Unlock()
	return result, nil
}

// windowDuration maps the schema enum to a Duration. Falls back to the 7d
// default for unknown values (the IsValid guard above already rejects them).
func windowDuration(w AgentMetricsWindow) time.Duration {
	switch w {
	case AgentMetricsWindowW24h:
		return 24 * time.Hour
	case AgentMetricsWindowW30d:
		return 30 * 24 * time.Hour
	default:
		return 7 * 24 * time.Hour
	}
}

// buildAgentMetricsRows groups attempts by axis, applies the window cutoff,
// and computes per-bucket aggregates. Output is sorted by attempt count
// descending then key ascending so the UI gets a stable ordering.
func buildAgentMetricsRows(attempts []agentmetrics.Attempt, cutoff time.Time, axis AgentMetricsAxis) []*AgentMetricsRow {
	type acc struct {
		durations    []int
		costs        []float64
		inTokens     []int
		outTokens    []int
		successes    int
		totalCost    float64
		lastFinished time.Time
	}
	groups := map[string]*acc{}
	for _, a := range attempts {
		if !a.StartedAt.IsZero() && a.StartedAt.Before(cutoff) {
			continue
		}
		key := axisKey(a, axis)
		if key == "" {
			continue
		}
		g, ok := groups[key]
		if !ok {
			g = &acc{}
			groups[key] = g
		}
		g.durations = append(g.durations, a.DurationMS)
		g.costs = append(g.costs, a.CostUSD)
		g.inTokens = append(g.inTokens, a.InputTokens)
		g.outTokens = append(g.outTokens, a.OutputTokens)
		g.totalCost += a.CostUSD
		if a.Bucket.Successful() {
			g.successes++
		}
		ts := a.FinishedAt
		if ts.IsZero() {
			ts = a.StartedAt
		}
		if !ts.IsZero() && ts.After(g.lastFinished) {
			g.lastFinished = ts
		}
	}

	out := make([]*AgentMetricsRow, 0, len(groups))
	for key, g := range groups {
		attemptCount := len(g.durations)
		row := &AgentMetricsRow{
			Key:              key,
			Attempts:         attemptCount,
			Successes:        g.successes,
			SuccessRate:      ratio(g.successes, attemptCount),
			MeanDurationMs:   meanInt(g.durations),
			P50DurationMs:    percentileInt(g.durations, 50),
			P95DurationMs:    percentileInt(g.durations, 95),
			MeanCostUsd:      meanFloat(g.costs),
			MeanInputTokens:  meanInt(g.inTokens),
			MeanOutputTokens: meanInt(g.outTokens),
		}
		if g.successes > 0 {
			eff := g.totalCost / float64(g.successes)
			row.EffectiveCostPerSuccessUsd = &eff
		}
		if !g.lastFinished.IsZero() {
			s := g.lastFinished.UTC().Format(time.RFC3339)
			row.LastSeenAt = &s
		}
		out = append(out, row)
	}
	sort.Slice(out, func(i, j int) bool {
		if out[i].Attempts != out[j].Attempts {
			return out[i].Attempts > out[j].Attempts
		}
		return out[i].Key < out[j].Key
	})
	return out
}

// axisKey extracts the bucket label for one Attempt against one axis. Empty
// string means "skip this attempt for this axis" (e.g. a model-axis bucket
// for a result.json with no model field).
func axisKey(a agentmetrics.Attempt, axis AgentMetricsAxis) string {
	switch axis {
	case AgentMetricsAxisModel:
		return a.Model
	case AgentMetricsAxisHarness:
		return a.Harness
	case AgentMetricsAxisProvider:
		return a.Provider
	case AgentMetricsAxisTier:
		return a.Tier
	}
	return ""
}

func ratio(num, denom int) float64 {
	if denom == 0 {
		return 0
	}
	return float64(num) / float64(denom)
}

func meanInt(xs []int) float64 {
	if len(xs) == 0 {
		return 0
	}
	var sum int
	for _, v := range xs {
		sum += v
	}
	return float64(sum) / float64(len(xs))
}

func meanFloat(xs []float64) float64 {
	if len(xs) == 0 {
		return 0
	}
	var sum float64
	for _, v := range xs {
		sum += v
	}
	return sum / float64(len(xs))
}

// percentileInt returns the nearest-rank percentile of xs (0-100). For p50 on
// an even-length slice it picks the lower of the two middle values; that
// matches Go's standard nearest-rank choice and is sufficient for the
// operator-facing summary.
func percentileInt(xs []int, p int) int {
	if len(xs) == 0 {
		return 0
	}
	sorted := append([]int(nil), xs...)
	sort.Ints(sorted)
	rank := (p * len(sorted)) / 100
	if rank >= len(sorted) {
		rank = len(sorted) - 1
	}
	return sorted[rank]
}

// agentMetricsFingerprint produces a stable revision string for the
// agentmetrics inputs at workingDir. The hash inputs are: the .ddx/exec/runs
// directory listing (name + size + modtime), the .ddx/executions directory
// listing of result.json files, and the .ddx/beads-archive.jsonl file's
// stat. Any add/remove/modify in those sources flips the fingerprint and
// invalidates the cache. The fingerprint survives ADR-004 archive moves
// because the archive file is included.
func agentMetricsFingerprint(workingDir string) string {
	h := sha256.New()
	addDir(h, filepath.Join(workingDir, ".ddx", "exec", "runs"), "")
	addDir(h, filepath.Join(workingDir, ".ddx", "executions"), "result.json")
	addStat(h, filepath.Join(workingDir, ".ddx", "beads-archive.jsonl"))
	addStat(h, filepath.Join(workingDir, ".ddx", "beads.jsonl"))
	return fmt.Sprintf("%x", h.Sum(nil))
}

func addDir(h interface{ Write([]byte) (int, error) }, dir, requireChild string) {
	entries, err := os.ReadDir(dir)
	if err != nil {
		fmt.Fprintf(writerOf(h), "missing:%s\n", dir)
		return
	}
	names := make([]string, 0, len(entries))
	for _, e := range entries {
		names = append(names, e.Name())
	}
	sort.Strings(names)
	for _, name := range names {
		full := filepath.Join(dir, name)
		if requireChild != "" {
			full = filepath.Join(full, requireChild)
		}
		addStat(h, full)
	}
}

func addStat(h interface{ Write([]byte) (int, error) }, path string) {
	info, err := os.Stat(path)
	if err != nil {
		fmt.Fprintf(writerOf(h), "absent:%s\n", path)
		return
	}
	fmt.Fprintf(writerOf(h), "%s:%d:%d\n", path, info.Size(), info.ModTime().UnixNano())
}

// writerOf adapts an io.Writer-like to fmt.Fprintf. Kept tiny so the helpers
// above stay one-liners.
func writerOf(h interface{ Write([]byte) (int, error) }) interface{ Write([]byte) (int, error) } {
	return h
}

package graphql

import (
	"context"
	"os"
	"path/filepath"
	"testing"
	"time"
)

// writeRun seeds one FEAT-010 run-store record under workingDir.
func writeRun(t *testing.T, workingDir, name, body string) {
	t.Helper()
	dir := filepath.Join(workingDir, ".ddx", "exec", "runs")
	if err := os.MkdirAll(dir, 0o755); err != nil {
		t.Fatalf("mkdir: %v", err)
	}
	if err := os.WriteFile(filepath.Join(dir, name), []byte(body), 0o644); err != nil {
		t.Fatalf("write: %v", err)
	}
}

// fixtureWorkingDir seeds three try-layer attempts that exercise every
// grouping axis: two attempts at claude/sonnet (one success, one failure),
// one at codex/gpt5 (success). Tokens are populated so the input/output
// token aggregates are non-zero.
func fixtureWorkingDir(t *testing.T) string {
	t.Helper()
	wd := t.TempDir()
	now := time.Now().UTC().Add(-1 * time.Hour).Format(time.RFC3339)
	end := time.Now().UTC().Format(time.RFC3339)
	writeRun(t, wd, "a.json", `{
		"id":"att-1","layer":"try","status":"success","outcome":"merged",
		"bead_id":"ddx-1","harness":"claude","provider":"anthropic","model":"sonnet",
		"cost_usd":1.0,"duration_ms":1000,"exit_code":0,
		"tokens_in":100,"tokens_out":50,
		"started_at":"`+now+`","completed_at":"`+end+`"
	}`)
	writeRun(t, wd, "b.json", `{
		"id":"att-2","layer":"try","status":"execution_failed","outcome":"failed",
		"bead_id":"ddx-2","harness":"claude","provider":"anthropic","model":"sonnet",
		"cost_usd":2.0,"duration_ms":3000,"exit_code":1,
		"tokens_in":200,"tokens_out":80,
		"started_at":"`+now+`","completed_at":"`+end+`"
	}`)
	writeRun(t, wd, "c.json", `{
		"id":"att-3","layer":"try","status":"already_satisfied","outcome":"merged",
		"bead_id":"ddx-3","harness":"codex","provider":"openai","model":"gpt5",
		"cost_usd":0.5,"duration_ms":500,"exit_code":0,
		"tokens_in":40,"tokens_out":20,
		"started_at":"`+now+`","completed_at":"`+end+`"
	}`)
	return wd
}

func newTestResolver(t *testing.T, wd string) *queryResolver {
	t.Helper()
	r, err := NewResolver(stubStateProvider{}, wd)
	if err != nil {
		t.Fatalf("NewResolver: %v", err)
	}
	return &queryResolver{Resolver: r}
}

// resetCache clears the process-global cache so each test sees a clean
// slate. Without this, tests that share an axis/window collide on cache
// hits and never rebuild against fresh fixtures.
func resetAgentMetricsCache() {
	agentMetricsCache.Lock()
	agentMetricsCache.byKey = map[string]agentMetricsCacheEntry{}
	agentMetricsCache.Unlock()
}

func TestAgentMetrics_GroupByModel(t *testing.T) {
	resetAgentMetricsCache()
	wd := fixtureWorkingDir(t)
	r := newTestResolver(t, wd)
	res, err := r.AgentMetrics(context.Background(), AgentMetricsWindowW7d, AgentMetricsAxisModel)
	if err != nil {
		t.Fatalf("AgentMetrics: %v", err)
	}
	if len(res.Rows) != 2 {
		t.Fatalf("model rows = %d, want 2", len(res.Rows))
	}
	// sonnet bucket: 2 attempts, 1 success.
	row := findRow(t, res.Rows, "sonnet")
	if row.Attempts != 2 || row.Successes != 1 {
		t.Fatalf("sonnet: %+v", row)
	}
	if row.SuccessRate != 0.5 {
		t.Fatalf("sonnet successRate = %f, want 0.5", row.SuccessRate)
	}
	// MeanCost = (1.0 + 2.0)/2 = 1.5; effective = 3.0/1 success = 3.0.
	if row.MeanCostUsd != 1.5 {
		t.Fatalf("sonnet meanCost = %f, want 1.5", row.MeanCostUsd)
	}
	if row.EffectiveCostPerSuccessUsd == nil || *row.EffectiveCostPerSuccessUsd != 3.0 {
		t.Fatalf("sonnet effectiveCost = %v, want 3.0", row.EffectiveCostPerSuccessUsd)
	}
	if row.MeanInputTokens != 150 || row.MeanOutputTokens != 65 {
		t.Fatalf("sonnet tokens: in=%f out=%f", row.MeanInputTokens, row.MeanOutputTokens)
	}
	// gpt5 bucket: 1 attempt, 1 success (already_satisfied counts).
	gpt := findRow(t, res.Rows, "gpt5")
	if gpt.Attempts != 1 || gpt.Successes != 1 {
		t.Fatalf("gpt5: %+v", gpt)
	}
	if res.Window != AgentMetricsWindowW7d || res.GroupBy != AgentMetricsAxisModel {
		t.Fatalf("echo fields: %+v", res)
	}
	if res.Revision == "" {
		t.Fatalf("revision must not be empty")
	}
}

func TestAgentMetrics_GroupByHarness(t *testing.T) {
	resetAgentMetricsCache()
	wd := fixtureWorkingDir(t)
	r := newTestResolver(t, wd)
	res, err := r.AgentMetrics(context.Background(), AgentMetricsWindowW24h, AgentMetricsAxisHarness)
	if err != nil {
		t.Fatalf("AgentMetrics: %v", err)
	}
	if len(res.Rows) != 2 {
		t.Fatalf("harness rows = %d, want 2", len(res.Rows))
	}
	claude := findRow(t, res.Rows, "claude")
	if claude.Attempts != 2 {
		t.Fatalf("claude attempts = %d, want 2", claude.Attempts)
	}
	codex := findRow(t, res.Rows, "codex")
	if codex.Attempts != 1 || codex.Successes != 1 {
		t.Fatalf("codex: %+v", codex)
	}
}

func TestAgentMetrics_GroupByProvider(t *testing.T) {
	resetAgentMetricsCache()
	wd := fixtureWorkingDir(t)
	r := newTestResolver(t, wd)
	res, err := r.AgentMetrics(context.Background(), AgentMetricsWindowW7d, AgentMetricsAxisProvider)
	if err != nil {
		t.Fatalf("AgentMetrics: %v", err)
	}
	if len(res.Rows) != 2 {
		t.Fatalf("provider rows = %d, want 2", len(res.Rows))
	}
	an := findRow(t, res.Rows, "anthropic")
	if an.Attempts != 2 {
		t.Fatalf("anthropic attempts = %d", an.Attempts)
	}
	op := findRow(t, res.Rows, "openai")
	if op.Attempts != 1 || op.Successes != 1 {
		t.Fatalf("openai: %+v", op)
	}
}

func TestAgentMetrics_GroupByTier(t *testing.T) {
	resetAgentMetricsCache()
	wd := fixtureWorkingDir(t)
	r := newTestResolver(t, wd)
	res, err := r.AgentMetrics(context.Background(), AgentMetricsWindowW30d, AgentMetricsAxisTier)
	if err != nil {
		t.Fatalf("AgentMetrics: %v", err)
	}
	if len(res.Rows) != 2 {
		t.Fatalf("tier rows = %d, want 2", len(res.Rows))
	}
	if findRow(t, res.Rows, "claude/sonnet").Attempts != 2 {
		t.Fatalf("claude/sonnet attempts != 2")
	}
	if findRow(t, res.Rows, "codex/gpt5").Attempts != 1 {
		t.Fatalf("codex/gpt5 attempts != 1")
	}
}

func TestAgentMetrics_WindowExcludesOldAttempts(t *testing.T) {
	resetAgentMetricsCache()
	wd := t.TempDir()
	old := time.Now().UTC().Add(-48 * time.Hour).Format(time.RFC3339)
	recent := time.Now().UTC().Add(-1 * time.Hour).Format(time.RFC3339)
	writeRun(t, wd, "old.json", `{
		"id":"old","layer":"try","status":"success",
		"harness":"claude","provider":"anthropic","model":"sonnet",
		"cost_usd":1,"duration_ms":1,"started_at":"`+old+`","completed_at":"`+old+`"
	}`)
	writeRun(t, wd, "new.json", `{
		"id":"new","layer":"try","status":"success",
		"harness":"claude","provider":"anthropic","model":"sonnet",
		"cost_usd":1,"duration_ms":1,"started_at":"`+recent+`","completed_at":"`+recent+`"
	}`)
	r := newTestResolver(t, wd)
	res, err := r.AgentMetrics(context.Background(), AgentMetricsWindowW24h, AgentMetricsAxisModel)
	if err != nil {
		t.Fatalf("AgentMetrics: %v", err)
	}
	row := findRow(t, res.Rows, "sonnet")
	if row.Attempts != 1 {
		t.Fatalf("24h window must exclude 48h-old attempt; got %d attempts", row.Attempts)
	}
}

// TestAgentMetrics_RevisionCache asserts the per-axis cache keys results on
// the run-store fingerprint and invalidates when a new run is added.
func TestAgentMetrics_RevisionCache(t *testing.T) {
	resetAgentMetricsCache()
	wd := fixtureWorkingDir(t)
	r := newTestResolver(t, wd)

	first, err := r.AgentMetrics(context.Background(), AgentMetricsWindowW7d, AgentMetricsAxisModel)
	if err != nil {
		t.Fatalf("first: %v", err)
	}
	// Same call returns identical pointer: cache hit.
	cached, err := r.AgentMetrics(context.Background(), AgentMetricsWindowW7d, AgentMetricsAxisModel)
	if err != nil {
		t.Fatalf("cached: %v", err)
	}
	if cached != first {
		t.Fatalf("expected cache hit (same pointer); got distinct results")
	}

	// Add a new attempt — fingerprint must change, cache must invalidate.
	now := time.Now().UTC().Format(time.RFC3339)
	writeRun(t, wd, "d.json", `{
		"id":"att-4","layer":"try","status":"success",
		"harness":"claude","provider":"anthropic","model":"sonnet",
		"cost_usd":1,"duration_ms":1,"started_at":"`+now+`","completed_at":"`+now+`"
	}`)
	updated, err := r.AgentMetrics(context.Background(), AgentMetricsWindowW7d, AgentMetricsAxisModel)
	if err != nil {
		t.Fatalf("updated: %v", err)
	}
	if updated == first {
		t.Fatalf("expected cache invalidation after new run; got same pointer")
	}
	if updated.Revision == first.Revision {
		t.Fatalf("revision should change when run-store changes")
	}
	row := findRow(t, updated.Rows, "sonnet")
	if row.Attempts != 3 {
		t.Fatalf("sonnet attempts after add = %d, want 3", row.Attempts)
	}
}

// TestAgentMetrics_RevisionSurvivesArchiveMove emulates the ADR-004 archive
// flow: closing a bead and moving its events into beads-archive.jsonl. The
// fingerprint must update so callers re-aggregate against the new state.
func TestAgentMetrics_RevisionSurvivesArchiveMove(t *testing.T) {
	resetAgentMetricsCache()
	wd := fixtureWorkingDir(t)
	r := newTestResolver(t, wd)
	first, err := r.AgentMetrics(context.Background(), AgentMetricsWindowW7d, AgentMetricsAxisModel)
	if err != nil {
		t.Fatalf("first: %v", err)
	}
	// Materialize an archive file — this is the ADR-004 archive surface.
	if err := os.MkdirAll(filepath.Join(wd, ".ddx"), 0o755); err != nil {
		t.Fatal(err)
	}
	if err := os.WriteFile(filepath.Join(wd, ".ddx", "beads-archive.jsonl"), []byte(`{"id":"x"}`+"\n"), 0o644); err != nil {
		t.Fatal(err)
	}
	second, err := r.AgentMetrics(context.Background(), AgentMetricsWindowW7d, AgentMetricsAxisModel)
	if err != nil {
		t.Fatalf("second: %v", err)
	}
	if first.Revision == second.Revision {
		t.Fatalf("revision should flip when beads-archive appears; got identical %q", first.Revision)
	}
}

